#!/bin/bash
# Generated by OrchestKit Claude Plugin
# Created: 2026-05-29

# Integration test: bin/validate-visual-style.py + bin/check-pr-visual-style.sh
#
# Guards the local Visual-Style pre-flight (the engine the CI workflow ALSO
# calls) against regressions, and asserts the workflow no longer carries its own
# copy of the vocabulary — so "clean locally" stays identical to "clean in CI".

set -euo pipefail

SCRIPT_DIR="$(cd "$(dirname "${BASH_SOURCE[0]}")" && pwd)"
PROJECT_ROOT="$(cd "$SCRIPT_DIR/../.." && pwd)"

RED='\033[0;31m'
GREEN='\033[0;32m'
NC='\033[0m'
PASS=0
FAIL=0
log_pass() { echo -e "  ${GREEN}PASS${NC} $1"; PASS=$((PASS + 1)); }
log_fail() { echo -e "  ${RED}FAIL${NC} $1 — $2"; FAIL=$((FAIL + 1)); }

echo "Visual-Style Validator Tests"
echo "============================"
cd "$PROJECT_ROOT"

VALIDATOR="bin/validate-visual-style.py"
WRAPPER="bin/check-pr-visual-style.sh"
WORKFLOW=".github/workflows/visual-style-lint.yml"

WORK="$(mktemp -d)"
trap 'rm -rf "$WORK"' EXIT

# UTF-8 byte sequences (octal) so the test file itself stays low-emoji.
ROCKET='\360\237\232\200'    # U+1F680 rocket
CHECK_OK='\342\234\205'      # U+2705 white check (allowed)
TARGET='\360\237\216\257'    # U+1F3AF target (allowed)
DINGBAT_TICK='\342\234\223'  # U+2713 check mark (forbidden — the trap)
DINGBAT_X='\342\234\227'     # U+2717 ballot X (forbidden)

# Run validator, capture exit code without tripping set -e.
run_validator() { local rc=0; python3 "$VALIDATOR" "$@" >/dev/null 2>&1 || rc=$?; echo "$rc"; }

# --- title mode -------------------------------------------------------------
printf 'fix(scope): plain ascii title' > "$WORK/title-clean.txt"
if [ "$(run_validator --mode title "$WORK/title-clean.txt")" = "0" ]; then
  log_pass "title: clean ASCII passes"
else
  log_fail "title clean" "expected exit 0"
fi

printf 'feat: ship it %b' "$ROCKET" > "$WORK/title-emoji.txt"
if [ "$(run_validator --mode title "$WORK/title-emoji.txt")" = "1" ]; then
  log_pass "title: any emoji fails"
else
  log_fail "title emoji" "expected exit 1 for rocket glyph"
fi

# --- body mode --------------------------------------------------------------
printf 'Status %b and goal %b reached.' "$CHECK_OK" "$TARGET" > "$WORK/body-ok.txt"
if [ "$(run_validator --mode body "$WORK/body-ok.txt")" = "0" ]; then
  log_pass "body: in-vocabulary emoji (white-check + target) passes"
else
  log_fail "body vocab" "expected exit 0 for allowed glyphs"
fi

printf 'done %b not %b' "$DINGBAT_TICK" "$DINGBAT_X" > "$WORK/body-dingbat.txt"
if [ "$(run_validator --mode body "$WORK/body-dingbat.txt")" = "1" ]; then
  log_pass "body: U+2713/U+2717 dingbats fail (the recurring trap)"
else
  log_fail "body dingbat" "expected exit 1 for U+2713/U+2717"
fi

# --env input path (used by the CI workflow)
if PR_BODY="clean body, no glyphs" python3 "$VALIDATOR" --mode body --env PR_BODY >/dev/null 2>&1; then
  log_pass "body: --env input path works (CI invocation shape)"
else
  log_fail "body --env" "expected exit 0 for clean env body"
fi

# --- wrapper ----------------------------------------------------------------
printf 'A clean body with no special glyphs.' > "$WORK/wrap-ok.txt"
if bash "$WRAPPER" --title "fix(x): clean" --body-file "$WORK/wrap-ok.txt" >/dev/null 2>&1; then
  log_pass "wrapper: clean title + body exits 0"
else
  log_fail "wrapper clean" "expected exit 0"
fi

printf 'oops %b' "$DINGBAT_TICK" > "$WORK/wrap-bad.txt"
if bash "$WRAPPER" --title "fix(x): ok" --body-file "$WORK/wrap-bad.txt" >/dev/null 2>&1; then
  log_fail "wrapper dingbat" "expected exit 1 for dingbat body"
else
  log_pass "wrapper: dingbat body exits non-zero"
fi

# --- drift guard ------------------------------------------------------------
# The workflow must DELEGATE to the validator, never embed its own vocabulary.
# A re-introduced inline VOCAB is exactly the drift this refactor removed.
if grep -q "validate-visual-style.py" "$WORKFLOW"; then
  log_pass "drift: workflow calls the shared validator"
else
  log_fail "drift: workflow delegation" "workflow no longer references validate-visual-style.py"
fi
if grep -q "VOCAB" "$WORKFLOW"; then
  log_fail "drift: inline vocab" "workflow re-introduced an inline VOCAB set (must delegate)"
else
  log_pass "drift: workflow carries no inline vocabulary"
fi

# Lock the vocabulary size (12 core + 3 risk + 3 ranking + VS16 + ZWJ = 20).
VOCAB_SIZE=$(python3 -c "import importlib.util,sys; \
spec=importlib.util.spec_from_file_location('v','bin/validate-visual-style.py'); \
m=importlib.util.module_from_spec(spec); spec.loader.exec_module(m); print(len(m.VOCAB))")
if [ "$VOCAB_SIZE" = "20" ]; then
  log_pass "vocab size locked at 20 (changes require updating src/rules/visual-style.md)"
else
  log_fail "vocab size" "expected 20, got $VOCAB_SIZE — sync with src/rules/visual-style.md"
fi

echo ""
echo "============================"
echo "  Results: $PASS passed, $FAIL failed"
echo "============================"
[ "$FAIL" -gt 0 ] && { echo -e "${RED}FAIL${NC}"; exit 1; }
echo -e "${GREEN}SUCCESS${NC}"
